const out = [];
for (const item of $input.all()) {
  const bin = item.binary || {};
  for (const key of Object.keys(bin)) {
    out.push({
      json: { source_file: bin[key].fileName || key },
      binary: { data: bin[key] },
      pairedItem: { item: 0 }
    });
  }
}
return out;

function isMissing(v) {
  if (v === null || v === undefined) return true;
  if (typeof v === 'string') {
    const t = v.trim().toLowerCase();
    return t === '' || t === 'null';
  }
  return false;
}

const critical = ['invoice_number', 'invoice_date', 'vendor_name', 'total_amount'];

const item = $input.first();
const data = item.json.data;
const filename = item.json.source_file ?? `File ${$runIndex + 1}`;

let status, missing = [];
if (!data || typeof data !== 'object' || Object.keys(data).length === 0) {
  status = '❌'; // extraction failed outright
} else {
  missing = critical.filter(k => isMissing(data[k]));
  status = missing.length === 0 ? '✅' : '❌';
}

// Accumulate across loop iterations so Build Summary can list every file.
// $runIndex === 0 is the first iteration of this run, so we reset there.
const store = $getWorkflowStaticData('global');
if ($runIndex === 0) store.invoiceBatch = [];
store.invoiceBatch.push({ source_file: filename, status });

// Keep `data` nested so 'Append row in sheet' can read $json.data.<field>
return [{
  json: { data, source_file: filename, status, missing_fields: missing.join(', ') },
  pairedItem: { item: 0 }
}];

const store = $getWorkflowStaticData('global');
const rows = store.invoiceBatch || [];
const total = rows.length;
const failed = rows.filter(r => r.status === '❌').length;

const header = failed === 0
  ? `All ${total} invoice(s) processed successfully.`
  : `${total - failed} of ${total} processed cleanly. ${failed} need a second look.`;

const list = rows.map(r => `${r.status} ${r.source_file}`).join('<br>');

return { json: { summary: `${header}<br><br>${list}` } };
